// ─── Snap UI: Profile Card Page ───────────────────────────────────
function profilePage(profile: Profile, remaining: number, base: string) {
  const bioText = profile.bio ? clamp(profile.bio, 100) : "";
  const metaText = `${profile.followers.toLocaleString()} followers`;
  const remText = remaining > 1 ? `${remaining} left today` : "Last one today";

  const elements: Record<string, any> = {
    page: {
      type: "stack",
      props: {},
      children: ["pfp", "name", ...(bioText ? ["bio"] : []), "meta", "separator", "remaining", "buttons"],
    },
    pfp: {
      type: "image",
      props: {
        url: profile.pfpUrl || "https://imagedelivery.net/BXluQx4ige9GuW0Ia56BHw/bc6c0c76-560a-4e16-0527-530997e68e00/rectcrop3",
        aspect: "1:1",
        alt: profile.displayName,
      },
    },
    name: {
      type: "item",
      props: {
        title: clamp(profile.displayName || profile.username, 100),
        description: `@${profile.username}`,
      },
    },
    meta: {
      type: "text",
      props: { content: metaText, size: "sm" as const, align: "center" as const },
    },
    separator: { type: "separator" as const, props: {} },
    remaining: {
      type: "text" as const,
      props: { content: remText, size: "sm" as const, align: "center" as const },
    },
    buttons: {
      type: "stack" as const,
      props: { direction: "horizontal" as const, gap: "md" as const },
      children: ["btn-pass", "btn-yass"],
    },
    "btn-pass": {
      type: "button" as const,
      props: { label: "Pass", variant: "secondary" as const },
      on: {
        press: {
          action: "submit" as const,
          params: { target: `${base}/?action=swipe_pass&tid=${profile.fid}` },
        },
      },
    },
    "btn-yass": {
      type: "button" as const,
      props: { label: "Yass", variant: "primary" as const },
      on: {
        press: {
          action: "submit" as const,
          params: { target: `${base}/?action=swipe_yass&tid=${profile.fid}` },
        },
      },
    },
  };

  if (bioText) {
    elements.bio = {
      type: "text",
      props: { content: bioText, size: "md" as const, align: "center" as const },
    };
  }

  return {
    version: SPEC,
    theme: { accent: "gray" as const },
    ui: { root: "page", elements },
