    ? createTursoDataStore()
    : createInMemoryDataStore();

// ─── Types ────────────────────────────────────────────────────────
interface NeynarUser {
  fid: number;
  username: string;
  display_name: string;
  pfp_url: string;
  profile: { bio: { text: string } };
  follower_count: number;
  following_count: number;
  power_badge: boolean;
  score: number;
  verifications: string[];
