        page: {
          type: "stack" as const,
          props: {},
          children: ["msg"],
        },
        msg: {
          type: "text" as const,
          props: {
            content: "All 3 swipes used. Resets at midnight UTC.",
            size: "md" as const,
            align: "center" as const,
          },
        },
      },
    },
  };
}

// ─── Snap UI: No More Profiles Page ───────────────────────────────
function noMorePage() {
  return {
    version: SPEC,
    theme: { accent: "gray" as const },
    ui: {
      root: "page",
      elements: {
        page: {
          type: "stack" as const,
          props: {},
          children: ["msg"],
        },
        msg: {
          type: "text" as const,
          props: {
            content: "No more profiles right now. Check back later.",
            size: "md" as const,
            align: "center" as const,
          },
        },
      },
    },
  };
}

// ─── Hono App ─────────────────────────────────────────────────────
const app = new Hono();

const snap: SnapFunction = async (ctx) => {
  const base = baseUrl(ctx.request);

  // ── GET: Gate page ──
  if (ctx.action.type === "get") {
    return gatePage(base);
  }

  // ── POST: Handle actions ──
  const fid = ctx.action.user.fid;
  const url = new URL(ctx.request.url);
  const action = url.searchParams.get("action") ?? "";
  const targetFidStr = url.searchParams.get("tid");

  // ── Gate: Pass button ──
  if (action === "gate_pass") {
    await setBehavioralTag(fid, "cautious");
    return await handleGateAction(fid, base);
  }

  // ── Gate: Yass button ──
  if (action === "gate_yass") {
    await setBehavioralTag(fid, "adventurous");
    return await handleGateAction(fid, base);
  }

  // ── Swipe: Pass ──
  if (action === "swipe_pass" && targetFidStr) {
    return await handleSwipe(fid, parseInt(targetFidStr), "pass", base);
  }

  // ── Swipe: Yass ──
  if (action === "swipe_yass" && targetFidStr) {
    return await handleSwipe(fid, parseInt(targetFidStr), "yass", base);
  }

  // Fallback
  return gatePage(base);
};

// ─── Gate Action Handler ──────────────────────────────────────────
async function handleGateAction(fid: number, base: string) {
  // Check if already qualified
  const existingQual = await getQualification(fid);
  if (existingQual?.qualified) {
    return await showNextProfile(fid, base);
  }

  // Run qualification (free tier)
  const user = await fetchUser(fid);
  if (!user) {
    return rejectionPage();
  }

  const qual = qualifyUser(user);
  await setQualification(fid, qual);

  if (!qual.qualified) {
    return rejectionPage();
  }

  // Qualified — show first profile
  return await showNextProfile(fid, base);
}

// ─── Swipe Handler ────────────────────────────────────────────────
async function handleSwipe(
  swiperFid: number,
  targetFid: number,
  direction: string,
  base: string
) {
  // Check daily limit
  const count = await getSwipeCount(swiperFid);
  if (count >= DAILY_SWIPE_LIMIT) {
    return dailyLimitPage();
  }

  // Record swipe
  const tag = (await getBehavioralTag(swiperFid)) ?? "unknown";
  await recordSwipe(swiperFid, targetFid, direction, tag);
  await incrementSwipe(swiperFid);

  // Show next profile
  return await showNextProfile(swiperFid, base);
}

// ─── Show Next Profile ────────────────────────────────────────────
async function showNextProfile(fid: number, base: string) {
  // Check daily limit
  const count = await getSwipeCount(fid);
  if (count >= DAILY_SWIPE_LIMIT) {
    return dailyLimitPage();
  }

  // Get remaining pool
  let pool = await getProfilePool(fid);
  const swiped = await getSwipedFids(fid);

  // Filter out already swiped
  pool = pool.filter((p) => !swiped.has(p.fid));

  // If pool is low, rebuild
  if (pool.length < 3) {
    const newProfiles = await buildProfilePool(fid);
    const existingFids = new Set(pool.map((p) => p.fid));
    for (const p of newProfiles) {
      if (!existingFids.has(p.fid) && !swiped.has(p.fid)) {
        pool.push(p);
        existingFids.add(p.fid);
      }
    }
    await setProfilePool(fid, pool);
  }

  if (pool.length === 0) {
    return noMorePage();
  }

  // Take the first profile
  const next = pool[0];
  await setProfilePool(fid, pool.slice(1));

  const remaining = DAILY_SWIPE_LIMIT - count;
  return profilePage(next, remaining, base);
}

// ─── Register Handler ─────────────────────────────────────────────
registerSnapHandler(app, snap);

export default app;
"}

